// Get raw input from webhook
// Webhook passes data directly in $json, not wrapped in body
const rawInput = $input.first()?.json || {};

// Check if this looks like a Telegram message
const message = rawInput.message || rawInput.channel_post || {};
const chat_id = message.chat?.id;
const text = message.text;

// If no message structure found, this is an invalid payload
if (!chat_id || !text) {
  return [{
    json: {
      isValid: false,
      error_code: "INVALID_PAYLOAD",
      error_message: "Missing chat_id or text in Telegram payload"
    }
  }];
}

// Valid payload - pass to NN_02
return [{
  json: {
    isValid: true,
    raw_input: rawInput
  }
}];

// Check NN_02 response
const nn02 = $input.first()?.json || {};

if (nn02.success === true && nn02.data) {
  return [{
    json: {
      nn02_success: true,
      nn02_data: nn02.data,
      nn02_meta: nn02._meta
    }
  }];
} else {
  return [{
    json: {
      nn02_success: false,
      nn02_error: nn02
    }
  }];
}

// Check NN_03 response
const nn03 = $input.first()?.json || {};

if (nn03.success === true && nn03.data?.ai_response) {
  return [{
    json: {
      nn03_success: true,
      ai_response: nn03.data.ai_response,
      chat_id: nn03.data.chat_id
    }
  }];
} else {
  return [{
    json: {
      nn03_success: false,
      nn03_error: nn03
    }
  }];
}

// Final response - Success
const nn04 = $input.first()?.json || {};

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      message_sent: nn04.success === true,
      chat_id: nn04.data?.chat_id
    },
    _meta: {
      source: "NN_01_Booking_Gateway",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_01",
      version: "1.0.0"
    }
  }
}];

// Error response for NN_02 failure
const nn02_error = $input.first()?.json?.nn02_error || $input.first()?.json || {};

return [{
  json: {
    success: false,
    error_code: nn02_error.error_code || "NN02_ERROR",
    error_message: nn02_error.error_message || "NN_02 processing failed",
    data: null,
    _meta: nn02_error._meta || {
      source: "NN_01_Booking_Gateway",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_01",
      version: "1.0.0"
    }
  }
}];

// Error response for NN_03 failure
const nn03_error = $input.first()?.json?.nn03_error || $input.first()?.json || {};

return [{
  json: {
    success: false,
    error_code: nn03_error.error_code || "NN03_ERROR",
    error_message: nn03_error.error_message || "NN_03 AI processing failed",
    data: null,
    _meta: nn03_error._meta || {
      source: "NN_01_Booking_Gateway",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_01",
      version: "1.0.0"
    }
  }
}];

// Error response for NN_04 failure
const nn04_error = $input.first()?.json || {};

return [{
  json: {
    success: false,
    error_code: nn04_error.error_code || "NN04_ERROR",
    error_message: nn04_error.error_message || "NN_04 Telegram sending failed",
    data: null,
    _meta: {
      source: "NN_01_Booking_Gateway",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_01",
      version: "1.0.0"
    }
  }
}];

// Error response for invalid input
const inputData = $input.first()?.json || {};

return [{
  json: {
    success: false,
    error_code: inputData.error_code || "INVALID_INPUT",
    error_message: inputData.error_message || "Invalid Telegram payload",
    data: null,
    _meta: {
      source: "NN_01_Booking_Gateway",
      timestamp: new Date().toISOString(),
      workflow_id: "NN_01",
      version: "1.0.0"
    }
  }
}];
